={{ JSON.stringify({
  type: $json.type || 'intel',
  source: $json.source || 'n8n',
  payload: {
    title: $json.title,
    summary: $json.summary,
    category: $json.category,
    importance: $json.importance,
    tags: $json.tags,
    timestamp: $json.timestamp || new Date().toISOString()
  }
}) }}
